"""Bad Apple!! Ultra - standalone player

Modes:
  python bad_apple_ultra.py              Braille mode (default)
  python bad_apple_ultra.py --color      Half-block + ANSI grayscale
  python bad_apple_ultra.py --gui        Pygame GUI window
  python bad_apple_ultra.py --invert     Invert colors (any mode)
"""

import zlib, base64, time, os, sys, io, tempfile

# Ensure UTF-8 output on Windows (for braille/half-block chars)
if sys.stdout.encoding != "utf-8":
    sys.stdout = io.TextIOWrapper(sys.stdout.buffer, encoding="utf-8", errors="replace")
    sys.stderr = io.TextIOWrapper(sys.stderr.buffer, encoding="utf-8", errors="replace")


def get_bit(packed, x, y):
    idx = y * W + x
    return (packed[idx // 8] >> (7 - idx % 8)) & 1


def decode_frames():
    raw = zlib.decompress(base64.b64decode(DATA))
    frames = []
    for i in range(FRAMES):
        off = i * BYTES_PER_FRAME
        frames.append(raw[off:off + BYTES_PER_FRAME])
    return frames


def init_audio():
    """Initialize audio from embedded AUDIO_DATA or external file. Returns True if ready."""
    try:
        import pygame
        pygame.mixer.init()
    except Exception:
        return False

    # Try embedded audio first
    if "AUDIO_DATA" in globals() and AUDIO_DATA:
        try:
            mp3_bytes = base64.b64decode(AUDIO_DATA)
            tmp = tempfile.NamedTemporaryFile(suffix=".mp3", delete=False)
            tmp.write(mp3_bytes)
            tmp.close()
            pygame.mixer.music.load(tmp.name)
            # Store path for cleanup
            init_audio._tmpfile = tmp.name
            return True
        except Exception:
            pass

    # Fallback to external file
    for name in ["audio.wav", "audio.mp3"]:
        path = os.path.join(os.path.dirname(os.path.abspath(__file__)), name)
        if os.path.exists(path):
            try:
                pygame.mixer.music.load(path)
                return True
            except Exception:
                pass
    pygame.mixer.quit()
    return False

init_audio._tmpfile = None


def cleanup_audio():
    import pygame
    try:
        pygame.mixer.music.stop()
        pygame.mixer.quit()
    except Exception:
        pass
    if init_audio._tmpfile:
        try:
            os.unlink(init_audio._tmpfile)
        except Exception:
            pass
        init_audio._tmpfile = None


def frame_to_braille(packed, invert=False):
    """Convert 160x120 bitmap to 80x30 braille characters."""
    DOT_BITS = [
        [0x01, 0x02, 0x04, 0x40],  # left column (dx=0), rows 0-3
        [0x08, 0x10, 0x20, 0x80],  # right column (dx=1), rows 0-3
    ]

    cols = W // 2
    rows = H // 4
    lines = []
    for by in range(rows):
        line = []
        for bx in range(cols):
            code = 0x2800
            px = bx * 2
            py = by * 4
            for dx in range(2):
                for dy in range(4):
                    bit = get_bit(packed, px + dx, py + dy)
                    if invert:
                        bit = 1 - bit
                    if bit:
                        code |= DOT_BITS[dx][dy]
            line.append(chr(code))
        lines.append("".join(line))
    return "\n".join(lines)


def frame_to_halfblock(packed, invert=False):
    """Convert to half-block chars with ANSI true-color grayscale."""
    cols = W // 2
    rows = H // 2
    lines = []
    for row_pair in range(0, rows, 2):
        line = []
        for col in range(cols):
            x = col * 2
            y_top = row_pair * 2
            y_bot = (row_pair + 1) * 2

            top_sum = 0
            bot_sum = 0
            for dx in range(2):
                for dy in range(2):
                    top_sum += get_bit(packed, x + dx, y_top + dy)
                    bot_sum += get_bit(packed, x + dx, y_bot + dy)

            if invert:
                top_v = int(top_sum / 4 * 255)
                bot_v = int(bot_sum / 4 * 255)
            else:
                top_v = int((1 - top_sum / 4) * 255)
                bot_v = int((1 - bot_sum / 4) * 255)

            line.append(f"\033[38;2;{top_v};{top_v};{top_v};48;2;{bot_v};{bot_v};{bot_v}m\u2580")
        line.append("\033[0m")
        lines.append("".join(line))
    return "\n".join(lines)


def play_terminal(mode="braille", invert=False):
    audio_playing = init_audio()

    print(f"Bad Apple!! Ultra [{mode}] - {FRAMES} frames @ {FPS:.0f}fps")
    print(f"Audio: {'ON' if audio_playing else 'OFF'}")
    print("Decoding frames...")
    frames = decode_frames()
    print("Press Ctrl+C to stop")
    time.sleep(1)

    # Enable virtual terminal on Windows
    if os.name == "nt":
        try:
            import ctypes
            k = ctypes.windll.kernel32
            h = k.GetStdHandle(-11)
            mode_val = ctypes.c_ulong()
            k.GetConsoleMode(h, ctypes.byref(mode_val))
            k.SetConsoleMode(h, mode_val.value | 0x0004)
        except Exception:
            pass

    os.system("cls" if os.name == "nt" else "clear")
    sys.stdout.write("\033[?25l")  # Hide cursor

    if audio_playing:
        import pygame
        pygame.mixer.music.play()

    frame_time = 1.0 / FPS
    frame_count = 0
    start_time = time.time()

    render = frame_to_braille if mode == "braille" else frame_to_halfblock

    try:
        for packed in frames:
            sys.stdout.write("\033[H")
            sys.stdout.write(render(packed, invert))
            sys.stdout.flush()

            frame_count += 1
            expected = start_time + frame_count * frame_time
            wait = expected - time.time()
            if wait > 0:
                time.sleep(wait)
    except KeyboardInterrupt:
        pass
    finally:
        sys.stdout.write("\033[?25h\033[0m")
        if audio_playing:
            cleanup_audio()
        elapsed = time.time() - start_time
        if elapsed > 0:
            print(f"\n\nPlayed {frame_count}/{FRAMES} frames in {elapsed:.1f}s "
                  f"({frame_count / elapsed:.1f} fps)")


def play_gui(invert=False):
    """Render in a pygame window with pixel-perfect scaling."""
    import pygame

    audio_playing = init_audio()

    print("Decoding frames...")
    frames = decode_frames()

    SCALE = 4
    win_w = W * SCALE
    win_h = H * SCALE

    pygame.init()
    screen = pygame.display.set_mode((win_w, win_h))
    pygame.display.set_caption("Bad Apple!!")

    if audio_playing:
        pygame.mixer.music.play()

    frame_idx = 0
    running = True
    start_time = time.time()
    frame_time = 1.0 / FPS

    while running and frame_idx < FRAMES:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            elif event.type == pygame.KEYDOWN and event.key == pygame.K_ESCAPE:
                running = False

        packed = frames[frame_idx]
        surf = pygame.Surface((W, H))
        pxarray = pygame.PixelArray(surf)
        for y in range(H):
            for x in range(W):
                bit = get_bit(packed, x, y)
                if invert:
                    val = 255 if bit else 0
                else:
                    val = 0 if bit else 255
                pxarray[x][y] = (val, val, val)
        del pxarray

        scaled = pygame.transform.scale(surf, (win_w, win_h))
        screen.blit(scaled, (0, 0))
        pygame.display.flip()

        frame_idx += 1
        expected = start_time + frame_idx * frame_time
        wait = expected - time.time()
        if wait > 0:
            pygame.time.wait(int(wait * 1000))

    pygame.quit()
    if audio_playing:
        cleanup_audio()
    elapsed = time.time() - start_time
    if elapsed > 0:
        print(f"Played {frame_idx} frames in {elapsed:.1f}s ({frame_idx / elapsed:.1f} fps)")


if __name__ == "__main__":
    args = sys.argv[1:]
    invert = "--invert" in args

    if "--gui" in args:
        play_gui(invert)
    elif "--color" in args:
        play_terminal("color", invert)
    else:
        play_terminal("braille", invert)
